<?php
namespace Tests\Feature;use App\Domain\Equipment\CharacterEquipmentSlot;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\Item;use App\Models\ItemInstance;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class CharacterEquipmentSchemaTest extends TestCase{use RefreshDatabase;public function test_schema_relations_uniqueness_and_existing_items_default_null(){$this->assertTrue(Schema::hasColumns('character_equipment',['character_id','slot','item_instance_id','equipped_at']));$this->assertNull(Item::first()?Item::first()->equipment_type:null);$indexes=collect(DB::select('SHOW INDEX FROM character_equipment'))->pluck('Key_name');$this->assertContains('character_equipment_owner_slot_unique',$indexes);$this->assertContains('character_equipment_instance_unique',$indexes);$rules=DB::select("SELECT DELETE_RULE FROM information_schema.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA=DATABASE() AND TABLE_NAME='character_equipment'");foreach($rules as $rule)$this->assertSame('RESTRICT',$rule->DELETE_RULE);$this->assertSame(9,count(CharacterEquipmentSlot::all()));}public function test_model_relations(){$character=Character::factory()->for(User::factory())->create();$item=Item::create(['code'=>'relation_sword','name'=>'Sword','item_type'=>'equipment','equipment_type'=>'weapon','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$instance=ItemInstance::factory()->create(['character_id'=>$character->id,'item_id'=>$item->id,'status'=>'equipped']);$row=CharacterEquipment::create(['character_id'=>$character->id,'slot'=>'main_hand','item_instance_id'=>$instance->id,'equipped_at'=>now()]);$this->assertTrue($row->character->is($character));$this->assertTrue($row->itemInstance->is($instance));$this->assertTrue($character->equipment->first()->is($row));}}
